def most_common_word(s):
    if not s:
        return ''

    words = s.lower().split()
    word_count = {}

    for word in words:
        if word in word_count:
            word_count[word] += 1
        else:
            word_count[word] = 1

    most_frequent = max(word_count.values())
    result = sorted([word for word, count in word_count.items() if count == most_frequent])

    return ' '.join(result[0])
